# ===========================================================================#  Hermes Gateway Tray Icon  ‚?"  hermes-tray.ps1  (v2 ‚?" PID-file based)#  Shows green/red/yellow circle based on gateway status.#  Left-click ‚+' live log tail   Right-click ‚+' context menu##  v2 changes (2026-06-07):#    - Test-GatewayRunning: reads gateway.pid instead of looking for hermes.exe#    - Restart-Gateway: uses hermes gateway stop + schtasks /Run (no duplicates)# ===========================================================================Add-Type -AssemblyName System.Windows.FormsAdd-Type -AssemblyName System.Drawing# ‚?"‚?" paths ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"$HermesExe     = "C:\Users\kenzo\AppData\Local\hermes\hermes-agent\venv\Scripts\hermes.exe"$GatewayLog    = "C:\Users\kenzo\AppData\Local\hermes\logs\gateway.log"$GatewayPidFile = "C:\Users\kenzo\AppData\Local\hermes\gateway.pid"$TelegramUrl   = "https://t.me/MiniHermesBot"$ScriptsDir    = "C:\Users\kenzo\AppData\Local\hermes\scripts"# ‚?"‚?" state ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"$script:LastStatus   = $null          # "UP" | "DOWN" | $null (first run)$script:UpSince      = $null          # datetime when gateway first seen UP$script:LogForm      = $null$script:LogTextBox   = $null$script:LogTailJob   = $null# ‚?"‚?" icon helpers ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function New-CircleIcon {    param(        [ValidateSet("Green","Red","Yellow")]        [string]$Color    )    $bmp  = New-Object System.Drawing.Bitmap(16, 16, [System.Drawing.Imaging.PixelFormat]::Format32bppArgb)    $g    = [System.Drawing.Graphics]::FromImage($bmp)    $g.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias    switch ($Color) {        "Green"  { $brush = [System.Drawing.Brushes]::LimeGreen   }        "Red"    { $brush = [System.Drawing.Brushes]::Crimson     }        "Yellow" { $brush = [System.Drawing.Brushes]::Gold        }    }    # Draw filled circle with thin dark border    $g.FillEllipse($brush, 1, 1, 14, 14)    $g.DrawEllipse([System.Drawing.Pens]::DarkGray, 1, 1, 14, 14)    $g.Dispose()    $ico = [System.Drawing.Icon]::FromHandle($bmp.GetHicon())    $bmp.Dispose()    return $ico}$script:IconGreen  = New-CircleIcon -Color Green$script:IconRed    = New-CircleIcon -Color Red$script:IconYellow = New-CircleIcon -Color Yellow# ‚?"‚?" gateway detection (v2: PID-file based) ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function Test-GatewayRunning {    # Primary: read gateway.pid and check if that PID is alive    if (Test-Path $GatewayPidFile) {        try {            $raw = Get-Content $GatewayPidFile -Raw -ErrorAction SilentlyContinue            if ($raw) {                $data = $raw | ConvertFrom-Json -ErrorAction SilentlyContinue                if ($data -and $data.pid) {                    $pidVal = [int]$data.pid                    $proc = Get-Process -Id $pidVal -ErrorAction SilentlyContinue                    if ($proc) { return $true }                }            }        } catch {            # Fall through to fallback        }    }    # Fallback: check if hermes gateway status reports running    try {        $result = & $HermesExe gateway status 2>$null        if ($result -match "running") { return $true }    } catch {}    return $false}# ‚?"‚?" tooltip text ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function Get-StatusTooltip {    param([string]$Status)    if ($Status -eq "UP") {        if ($script:UpSince) {            $elapsed = (Get-Date) - $script:UpSince            $hours   = [math]::Floor($elapsed.TotalHours)            $mins    = $elapsed.Minutes            return "Hermes: UP (${hours}h ${mins}m)"        }        return "Hermes: UP"    }    return "Hermes: DOWN"}# ‚?"‚?" live log window ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function Show-LiveLog {    # If already open, bring to front    if ($script:LogForm -and !$script:LogForm.IsDisposed) {        $script:LogForm.Activate()        return    }    $script:LogForm = New-Object System.Windows.Forms.Form    $script:LogForm.Text          = "Hermes Gateway Log"    $script:LogForm.Size          = New-Object System.Drawing.Size(800, 500)    $script:LogForm.StartPosition = "CenterScreen"    $script:LogForm.Icon          = $script:IconGreen    $script:LogTextBox = New-Object System.Windows.Forms.TextBox    $script:LogTextBox.Multiline  = $true    $script:LogTextBox.ScrollBars = "Vertical"    $script:LogTextBox.Font       = New-Object System.Drawing.Font("Consolas", 9)    $script:LogTextBox.Dock       = "Fill"    $script:LogTextBox.ReadOnly   = $true    $script:LogTextBox.BackColor  = [System.Drawing.Color]::FromArgb(30, 30, 30)    $script:LogTextBox.ForeColor  = [System.Drawing.Color]::FromArgb(200, 220, 200)    $script:LogForm.Controls.Add($script:LogTextBox)    # Pre-populate with last 200 lines if log exists    if (Test-Path $GatewayLog) {        try {            $tail = Get-Content $GatewayLog -Tail 200 -ErrorAction SilentlyContinue            if ($tail) {                $script:LogTextBox.Lines = $tail                $script:LogTextBox.SelectionStart = $script:LogTextBox.Text.Length                $script:LogTextBox.ScrollToCaret()            }        } catch {}    }    # Start background job to tail the log    $script:LogTailJob = Start-Job -ScriptBlock {        param($logPath)        Get-Content $logPath -Wait -Tail 0 2>$null    } -ArgumentList $GatewayLog    # Timer to pump new log lines into the text box    $logTimer = New-Object System.Windows.Forms.Timer    $logTimer.Interval = 1000    $logTimer.Add_Tick({        if ($script:LogTailJob -and $script:LogTextBox -and !$script:LogTextBox.IsDisposed) {            $newLines = Receive-Job $script:LogTailJob -ErrorAction SilentlyContinue            if ($newLines) {                $script:LogTextBox.AppendText(($newLines -join "`r`n") + "`r`n")                # Cap at 5000 lines to avoid memory issues                if ($script:LogTextBox.Lines.Count -gt 5000) {                    $trimmed = $script:LogTextBox.Lines | Select-Object -Skip ($script:LogTextBox.Lines.Count - 3000)                    $script:LogTextBox.Lines = $trimmed                }                $script:LogTextBox.SelectionStart = $script:LogTextBox.Text.Length                $script:LogTextBox.ScrollToCaret()            }        }    })    $logTimer.Start()    # Cleanup on close    $script:LogForm.Add_FormClosing({        $logTimer.Stop()        $logTimer.Dispose()        if ($script:LogTailJob) {            Stop-Job  $script:LogTailJob -ErrorAction SilentlyContinue            Remove-Job $script:LogTailJob -Force -ErrorAction SilentlyContinue            $script:LogTailJob = $null        }    })    $script:LogForm.Show() | Out-Null}# ‚?"‚?" restart gateway (v2: clean stop + schtasks start) ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function Restart-Gateway {    # Stop gateway cleanly via hermes CLI    try {        & $HermesExe gateway stop 2>$null        Start-Sleep -Seconds 3    } catch {}    # Start via scheduled task (single process chain, no duplicates)    try {        schtasks /Run /TN Hermes_Gateway 2>$null    } catch {        # Fallback: direct start        Start-Process -FilePath $HermesExe -ArgumentList "gateway", "run" -WindowStyle Hidden    }    # Force an immediate status check    $script:LastStatus = $null    Update-Status}# ‚?"‚?" status update ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"function Update-Status {    $notifyIcon = $script:TrayIcon    if (-not $notifyIcon) { return }    # Set yellow (checking) icon while we probe    $notifyIcon.Icon = $script:IconYellow    $isRunning = Test-GatewayRunning    $newStatus = if ($isRunning) { "UP" } else { "DOWN" }    # Update icon and tooltip    if ($newStatus -eq "UP") {        $notifyIcon.Icon = $script:IconGreen        if ($script:UpSince -eq $null) {            $script:UpSince = Get-Date        }    } else {        $notifyIcon.Icon = $script:IconRed        $script:UpSince = $null    }    $notifyIcon.Text = Get-StatusTooltip -Status $newStatus    # Balloon notification on status change    if ($script:LastStatus -ne $null -and $script:LastStatus -ne $newStatus) {        if ($newStatus -eq "UP") {            $notifyIcon.ShowBalloonTip(5000, "Hermes Gateway", "Gateway is UP", "Info")        } else {            $notifyIcon.ShowBalloonTip(5000, "Hermes Gateway", "Gateway is DOWN!", "Error")        }    }    $script:LastStatus = $newStatus}# ‚?"‚?" build tray icon & menu ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"$script:TrayIcon = New-Object System.Windows.Forms.NotifyIcon$script:TrayIcon.Icon  = $script:IconYellow$script:TrayIcon.Text  = "Hermes: Checking..."$script:TrayIcon.Visible = $true# Context menu (right-click)$contextMenu = New-Object System.Windows.Forms.ContextMenuStrip$itemLiveLog = New-Object System.Windows.Forms.ToolStripMenuItem$itemLiveLog.Text = "Live Log"$itemLiveLog.Add_Click({ Show-LiveLog })$itemRestart = New-Object System.Windows.Forms.ToolStripMenuItem$itemRestart.Text = "Restart Gateway"$itemRestart.Add_Click({ Restart-Gateway })$itemTelegram = New-Object System.Windows.Forms.ToolStripMenuItem$itemTelegram.Text = "Open Telegram"$itemTelegram.Add_Click({ Start-Process $TelegramUrl })$itemSep = New-Object System.Windows.Forms.ToolStripSeparator$itemExit = New-Object System.Windows.Forms.ToolStripMenuItem$itemExit.Text = "Exit"$itemExit.Add_Click({    # Cleanup    $script:TrayIcon.Visible = $false    $script:TrayIcon.Dispose()    if ($script:LogTailJob) {        Stop-Job  $script:LogTailJob -ErrorAction SilentlyContinue        Remove-Job $script:LogTailJob -Force -ErrorAction SilentlyContinue    }    if ($script:LogForm -and !$script:LogForm.IsDisposed) {        $script:LogForm.Close()    }    # Dispose icons    $script:IconGreen.Dispose()    $script:IconRed.Dispose()    $script:IconYellow.Dispose()    [System.Windows.Forms.Application]::Exit()})$contextMenu.Items.AddRange(@($itemLiveLog, $itemRestart, $itemTelegram, $itemSep, $itemExit))$script:TrayIcon.ContextMenuStrip = $contextMenu# Left-click ‚+' open live log$script:TrayIcon.Add_Click({    if ($_.Button -eq [System.Windows.Forms.MouseButtons]::Left) {        Show-LiveLog    }})# ‚?"‚?" polling timer ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"$pollTimer = New-Object System.Windows.Forms.Timer$pollTimer.Interval = 30000   # 30 seconds$pollTimer.Add_Tick({ Update-Status })$pollTimer.Start()# ‚?"‚?" initial check ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"Update-Status# ‚?"‚?" run message loop ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"[System.Windows.Forms.Application]::Run()# ‚?"‚?" cleanup on exit ‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"‚?"$pollTimer.Stop()$pollTimer.Dispose()$contextMenu.Dispose()$script:TrayIcon.Dispose()$script:IconGreen.Dispose()$script:IconRed.Dispose()$script:IconYellow.Dispose()